def unique_root_tags(spec: dict) -> int {
    for old in [root -->] { root del --> old; }
    for t in list(spec["tags"]) {
        if str(t) not in [n.name for n in [root -->][?:Tag]] {
            root ++> Tag(name=str(t));
        }
    }
    return (root spawn TagCount()).count;
}

