def hops_from_root(spec: dict) -> int:
    """Fewest hops from root to the named station (-1 if unreachable)."""
    frontier = [(g, 1) for g in spec["gateways"]]
    seen = []
    while frontier:
        (name, d) = frontier.pop(0)
        if name == spec["target"]:
            return d
        if name in seen:
            continue
        seen.append(name)
        for nxt in spec["links"].get(name, []):
            frontier.append((nxt, d + 1))
    return -1

