def settings_registry(spec: dict) -> str:
    """Render root's settings registry after applying known overrides."""
    reg = {}
    for (k, v) in spec["defaults"].items():
        reg[k] = str(v)
    for (k, v) in spec["overrides"].items():
        if k in reg:
            reg[k] = str(v)
    entries = []
