def registry_depth(spec: dict) -> int:
    """Depth of the deepest entry in root's fan-out tree (tops sit at 1)."""
    deepest = 0
    frontier = [(t, 1) for t in spec["tops"]]
    while frontier:
        (name, d) = frontier.pop(0)
        if d > deepest:
            deepest = d
        for c in spec["tree"].get(name, []):
            frontier.append((c, d + 1))
    return deepest

