def nearest_beacon(spec: dict) -> str:
    """Closest lit beacon to root as name@depth (ties alphabetical)."""
    frontier = [(g, 1) for g in spec["gateways"]]
    seen = []
    hits = []
    while frontier:
        (name, d) = frontier.pop(0)
        if name in seen:
            continue
        seen.append(name)
        if name in spec["lit"]:
            hits.append((d, name))
        for nxt in spec["links"].get(name, []):
            frontier.append((nxt, d + 1))
    if not hits:
        return "dark"
    hits.sort()
    return hits[0][1] + "@" + str(hits[0][0])

